/// <summary>
/// Extension class of <c>CustPostInvoice</c> for text block management
/// </summary>
[ExtensionOf(classStr(CustPostInvoice))]
final class FWFTextBlockCustPostInvoice_Extension
{
}

Method.Source:
protected void postCustInvoice(CustInvoiceJour _custInvoiceJour, LedgerVoucher _ledgerVoucher, boolean _creditNote, NumberSeq _numberSeq)
{
    CustInvoiceTrans custInvoiceTransLocal;
    ;
    next postCustInvoice(_custInvoiceJour, _ledgerVoucher, _creditNote, _numberSeq);

    while select custInvoiceTransLocal
        where custInvoiceTransLocal.SalesId == _custInvoiceJour.SalesId
            && custInvoiceTransLocal.InvoiceId == _custInvoiceJour.InvoiceId
            && custInvoiceTransLocal.InvoiceDate == _custInvoiceJour.InvoiceDate
            && custInvoiceTransLocal.numberSequenceGroup == _custInvoiceJour.numberSequenceGroup
    {
        FWFTextBlockEventHandler::newParameters(custInvoiceTransLocal, EventLogType::Insert).run();
    }

    FWFTextBlockEventHandler::newParameters(_custInvoiceJour, EventLogType::Insert).run();
}
